import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).parents[1] / "src"))

import unittest

from reporting_cli import Report, ReportItem, build_report


class ReportFormattingTests(unittest.TestCase):
    def setUp(self) -> None:
        self.report = Report(
            "Weekly delivery",
            (
                ReportItem("Parcel A", "Arrived at the depot", "ok"),
                ReportItem("Parcel B", "Address needs review", "warn"),
            ),
        )

    def test_compact_policy_keeps_one_line_items(self) -> None:
        self.assertEqual(
            build_report(self.report, "compact"),
            "Weekly delivery\nok: Parcel A\nwarn: Parcel B",
        )

    def test_verbose_policy_keeps_labeled_details(self) -> None:
        self.assertEqual(
            build_report(self.report, "verbose"),
            "\n".join(
                (
                    "Report: Weekly delivery",
                    "Items: 2",
                    "- Name: Parcel A",
                    "  Status: ok",
                    "  Detail: Arrived at the depot",
                    "- Name: Parcel B",
                    "  Status: warn",
                    "  Detail: Address needs review",
                )
            ),
        )

    def test_unknown_policy_is_rejected(self) -> None:
        with self.assertRaises(ValueError):
            build_report(self.report, "default")  # type: ignore[arg-type]


if __name__ == "__main__":
    unittest.main()

