def format_compact(report: ReportLike) -> str:
    lines = [report.title]
    lines.extend(f"{item.status}: {item.name}" for item in report.items)
    return "\n".join(lines)


def format_verbose(report: ReportLike) -> str:
    lines = [f"Report: {report.title}", f"Items: {len(report.items)}"]
    for item in report.items:
        lines.extend(
            (
                f"- Name: {item.name}",
                f"  Status: {item.status}",
                f"  Detail: {item.detail}",
            )
        )
    return "\n".join(lines)


def format_enhanced(report: ReportLike) -> str:
    """Format a report with visual separators and breathing room for human scanning."""
    lines = [
        report.title,
        "=" * len(report.title),
        "",
    ]
    for i, item in enumerate(report.items):
        if i > 0:
            lines.append("")
        lines.append(f"{item.status}: {item.name}")
        lines.append(f"    {item.detail}")
    return "\n".join(lines)
